-- Database schema for DesignTattva Project\n\n-- Projects Table\nCREATE TABLE Projects (\n    ProjectID INT PRIMARY KEY AUTO_INCREMENT,\n    ProjectName VARCHAR(255) NOT NULL,\n    StartDate DATETIME NOT NULL,\n    EndDate DATETIME,\n    Status ENUM('Pending', 'In Progress', 'Completed') NOT NULL\n);\n\n-- Customers Table\nCREATE TABLE Customers (\n    CustomerID INT PRIMARY KEY AUTO_INCREMENT,\n    CustomerName VARCHAR(255) NOT NULL,\n    ContactEmail VARCHAR(255) NOT NULL,\n    Phone VARCHAR(15),\n    Address TEXT\n);\n\n-- Service Vendors Table\nCREATE TABLE ServiceVendors (\n    VendorID INT PRIMARY KEY AUTO_INCREMENT,\n    VendorName VARCHAR(255) NOT NULL,\n    ContactEmail VARCHAR(255) NOT NULL,\n    Phone VARCHAR(15)\n);\n\n-- Material Vendors Table\nCREATE TABLE MaterialVendors (\n    VendorID INT PRIMARY KEY AUTO_INCREMENT,\n    VendorName VARCHAR(255) NOT NULL,\n    ContactEmail VARCHAR(255) NOT NULL,\n    Phone VARCHAR(15)\n);\n\n-- Expenses Table\nCREATE TABLE Expenses (\n    ExpenseID INT PRIMARY KEY AUTO_INCREMENT,\n    ProjectID INT,\n    Description TEXT,\n    Amount DECIMAL(10, 2) NOT NULL,\n    DateIncurred DATETIME NOT NULL,\n    FOREIGN KEY (ProjectID) REFERENCES Projects(ProjectID) ON DELETE CASCADE\n);\n\n-- Customer Invoices Table\nCREATE TABLE CustomerInvoices (\n    InvoiceID INT PRIMARY KEY AUTO_INCREMENT,\n    CustomerID INT,\n    ProjectID INT,\n    Amount DECIMAL(10, 2) NOT NULL,\n    InvoiceDate DATETIME NOT NULL,\n    Paid BOOLEAN DEFAULT FALSE,\n    FOREIGN KEY (CustomerID) REFERENCES Customers(CustomerID) ON DELETE CASCADE,\n    FOREIGN KEY (ProjectID) REFERENCES Projects(ProjectID) ON DELETE CASCADE\n);\n\n-- Payments Table\nCREATE TABLE Payments (\n    PaymentID INT PRIMARY KEY AUTO_INCREMENT,\n    InvoiceID INT,\n    Amount DECIMAL(10, 2) NOT NULL,\n    PaymentDate DATETIME NOT NULL,\n    FOREIGN KEY (InvoiceID) REFERENCES CustomerInvoices(InvoiceID) ON DELETE CASCADE\n);\n\n-- Receipts Table\nCREATE TABLE Receipts (\n    ReceiptID INT PRIMARY KEY AUTO_INCREMENT,\n    PaymentID INT,\n    ReceiptDate DATETIME NOT NULL,\n    Amount DECIMAL(10, 2) NOT NULL,\n    FOREIGN KEY (PaymentID) REFERENCES Payments(PaymentID) ON DELETE CASCADE\n);\n